using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tarefa #28 — regeneração automática de vida, disponível por defeito no modo
/// normal (sem precisar de upgrade). Regras:
///
/// - Só começa depois de o player passar <see cref="delayAfterDamage"/>
///   segundos sem receber dano (reinicia sempre que <see cref="PlayerCombat.OnPlayerDamaged"/> dispara).
/// - Lenta e gradual: recupera 1 coração a cada <see cref="regenInterval"/> segundos.
/// - Pára (e reinicia a espera) imediatamente ao receber dano.
/// - Não funciona durante bosses nem em qualquer estado "bloqueado" — ver
///   <see cref="SetBlocked"/> (referência contada; <see cref="BossHealthBarUI"/>
///   já está ligado aqui, e outros sistemas — ex: alerta/perseguição de
///   inimigos — podem usar a mesma API no futuro).
/// - Pára ao chegar à vida máxima.
/// - Completamente desactivada quando <see cref="PlayerProgress.IsHardModeActive"/> (Juramento Difícil).
/// - Independente da Pele Serena (não interfere com esta regeneração).
/// - Brotos de Vida e itens de cura continuam a funcionar normalmente — não
///   passam por este componente, usam directamente <see cref="PlayerProgress.Heal"/>.
/// </summary>
[RequireComponent(typeof(PlayerCombat))]
public class PlayerHealthRegen : MonoBehaviour
{
    /// <summary>Singleton simples (1 player), para sistemas como BossHealthBarUI bloquearem a regen sem precisar de referência directa ao player.</summary>
    public static PlayerHealthRegen Instance { get; private set; }

    [Header("Regeneração Automática (Tarefa #28)")]
    [Tooltip("Segundos sem receber dano antes de a regeneração começar (ou recomeçar, depois de ser interrompida).")]
    [SerializeField] private float delayAfterDamage = 5f;

    [Tooltip("Segundos entre cada coração regenerado.")]
    [SerializeField] private float regenInterval = 3f;

    private PlayerCombat combat;
    private float noDamageTimer;
    private float regenTimer;

    // Bloqueio com referência contada — vários sistemas podem bloquear em simultâneo (ex: boss + zona de perigo).
    private readonly HashSet<object> blockers = new HashSet<object>();

    /// <summary>True enquanto qualquer sistema tiver bloqueado a regeneração (ver <see cref="SetBlocked"/>).</summary>
    public bool IsBlocked => blockers.Count > 0;

    private void Awake()
    {
        Instance = this;
        combat = GetComponent<PlayerCombat>();
    }

    private void OnDestroy()
    {
        if (Instance == this) Instance = null;
    }

    private void OnEnable()
    {
        if (combat != null) combat.OnPlayerDamaged += OnPlayerDamaged;
    }

    private void OnDisable()
    {
        if (combat != null) combat.OnPlayerDamaged -= OnPlayerDamaged;
    }

    private void OnPlayerDamaged(DamageInfo info, int finalAmount)
    {
        noDamageTimer = 0f;
        regenTimer = 0f;
    }

    private void Update()
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        // Juramento Difícil desactiva completamente a regeneração automática.
        if (progress.IsHardModeActive) { noDamageTimer = 0f; regenTimer = 0f; return; }

        // Bosses / estados de perigo bloqueiam a regeneração (ver SetBlocked).
        if (IsBlocked) { noDamageTimer = 0f; regenTimer = 0f; return; }

        // Já está à vida máxima — nada a fazer.
        if (progress.currentHearts >= progress.maxHearts) { noDamageTimer = 0f; regenTimer = 0f; return; }

        noDamageTimer += Time.deltaTime;
        if (noDamageTimer < delayAfterDamage) return;

        regenTimer += Time.deltaTime;
        if (regenTimer >= regenInterval)
        {
            regenTimer = 0f;
            progress.Heal(1);
        }
    }

    /// <summary>
    /// Bloqueia/desbloqueia a regeneração automática enquanto "source"
    /// estiver registado. Referência contada: a regen só corre quando NENHUM
    /// "source" estiver a bloquear. Usado por <see cref="BossHealthBarUI"/>
    /// (Show/Hide) para impedir regen durante bosses; outros sistemas (ex:
    /// estado de perigo/combate de inimigos) podem chamar esta mesma API com
    /// a sua própria chave.
    /// </summary>
    public void SetBlocked(object source, bool blocked)
    {
        if (source == null) return;
        if (blocked) blockers.Add(source);
        else blockers.Remove(source);
    }
}
